#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e5+10,BK=384;int blk,n,m,Q,a[N];
int loc[N],s[N/BK+10][N],S[N/BK+10][N/BK+10],ql[N],qr[N],Ans,c[N],stk[N],top,L=0,R=1;
inline void ins(const int &x)
{
	++c[stk[++top]=x];int q=c[x]+s[R-1][x]-s[L][x];
	if(q!=1&&(q&1))--Ans;else if(!(q&1))++Ans;
//	printf("ins %d :: %d %d (%d,%d)\n",x,q,Ans,L,R);
}
inline void ClearAll(){while(top)c[stk[top--]]=0;}
int main()
{
	n=read();m=read();Q=read();
	rep(1,n,i)a[i]=read(),loc[i]=(i-1)/BK+1;blk=loc[n];
	rep(1,blk,i)ql[i]=qr[i-1]+1,qr[i]=i*BK;qr[blk]=n;
	rep(1,blk,L)
	{
		int r=qr[L-1];Ans=0;
		rep(L,blk,R){while(r<qr[R])ins(a[++r]);S[L][R]=Ans;}
		ClearAll();
	}
//	Ans=0;rep(1,5,i)ins(a[i]);printf("debug :: %d\n",Ans);
	rep(1,blk,i)
	{
		memcpy(s[i],s[i-1],(m+3)<<2);
		rep(ql[i],qr[i],j)++s[i][a[j]];
	}
	Ans=0;while(Q--)
	{
		int l=(read()+Ans)%n+1;
		int r=(read()+Ans)%n+1;
		if(l>r){int tmp=l;l=r;r=tmp;}
//		printf("query %d %d\n",l,r);
		L=loc[l];R=loc[r];Ans=0;
		if(L==R){L=0;R=1;rep(l,r,i)ins(a[i]);printf("%d\n",Ans);}
		else
		{
			Ans=S[L+1][R-1];
			rep(l,qr[L],i)ins(a[i]);
			rep(ql[R],r,i)ins(a[i]);
			printf("%d\n",Ans);
		}
		ClearAll();
	}
	return 0;
}
